                      <span style={{ width: 10, height: 10, borderRadius: 2, flexShrink: 0, background: isCtrl ? "rgba(220,220,220,0.5)" : DEFAULT_COLORS[gi % DEFAULT_COLORS.length], display: "inline-block" }} />
