// ─── AI ASSISTANT ───────────────────────────────────────────────────────────
function AIAssistant({ context }) {
  const [open, setOpen] = useState(false);
  const [msgs, setMsgs] = useState([{
    role: "assistant",
    content: "Hello! I'm the LemanFenix AI research assistant. I have full context on your experiments, compounds, and survival data. Ask me anything."
  }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [msgs]);

  const send = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role: "user", content: input };
    const newMsgs = [...msgs, userMsg];
    setMsgs(newMsgs); setInput(""); setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: `You are the AI research assistant for LemanFenix, a biotech startup developing heat-stress protection additives for broiler chickens during transport. You have deep knowledge of all experiments, compounds (LM codes), survival analysis, and scientific context. Current context:\n\n${context}\n\nBe concise, scientifically precise, and use exact compound/experiment IDs.`,
          messages: newMsgs.map(m => ({ role: m.role, content: m.content }))
        })
      });
      const data = await res.json();
      const reply = data.content?.[0]?.text || "Could not generate response.";
      setMsgs(m => [...m, { role: "assistant", content: reply }]);
    } catch (e) {
      setMsgs(m => [...m, { role: "assistant", content: "Connection error. Please retry." }]);
    }
    setLoading(false);
  };

  return (
    <>
      <button onClick={() => setOpen(o => !o)} title="AI Research Assistant" style={{
        position: "fixed", bottom: 24, right: 24, width: 50, height: 50,
        borderRadius: "50%", background: `linear-gradient(135deg,${GOLD},${GOLD2})`,
        border: "none", cursor: "pointer", fontSize: 22, boxShadow: `0 4px 24px rgba(190,165,75,0.4)`,
        zIndex: 2000, display: "flex", alignItems: "center", justifyContent: "center"
      }}>✦</button>

      {open && (
        <div style={{
          position: "fixed", bottom: 86, right: 24, width: 375, height: 480,
          background: BG2, border: `1px solid ${BORDER}`, borderRadius: 14,
          display: "flex", flexDirection: "column", zIndex: 2000,
          boxShadow: "0 24px 64px rgba(0,0,0,0.85)"
        }}>
          <div style={{ padding: "14px 16px", borderBottom: `1px solid rgba(255,255,255,0.07)`, display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ color: GOLD, fontSize: 14 }}>✦</span>
            <span style={{ color: "white", fontWeight: 700, fontSize: 13, letterSpacing: "0.06em" }}>AI Research Assistant</span>
            <button onClick={() => setOpen(false)} style={{ marginLeft: "auto", background: "none", border: "none", color: "rgba(255,255,255,0.35)", cursor: "pointer", fontSize: 20, lineHeight: 1 }}>×</button>
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: "12px 14px", display: "flex", flexDirection: "column", gap: 10 }}>
            {msgs.map((m, i) => (
              <div key={i} style={{
                alignSelf: m.role === "user" ? "flex-end" : "flex-start",
                maxWidth: "88%",
                background: m.role === "user" ? `rgba(190,165,75,0.12)` : "rgba(255,255,255,0.05)",
                border: m.role === "user" ? `1px solid rgba(190,165,75,0.3)` : "1px solid rgba(255,255,255,0.07)",
                borderRadius: 10, padding: "9px 12px",
                color: "rgba(255,255,255,0.85)", fontSize: 12.5, lineHeight: 1.55, whiteSpace: "pre-wrap"
              }}>{m.content}</div>
            ))}
            {loading && <div style={{ color: "rgba(190,165,75,0.5)", fontSize: 12, alignSelf: "flex-start" }}>Thinking…</div>}
            <div ref={endRef} />
          </div>
          <div style={{ padding: "10px 12px", borderTop: `1px solid rgba(255,255,255,0.07)`, display: "flex", gap: 8 }}>
            <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()}
              placeholder="Ask about your research…"
              style={{ ...s.input, flex: 1, padding: "7px 11px", fontSize: 12.5, marginBottom: 0 }} />
            <button onClick={send} disabled={loading} style={{ ...s.btnGold, padding: "7px 14px" }}>→</button>
          </div>
        </div>
      )}
    </>
  );
}

