// ─── RAW UPLOAD ZONE ─────────────────────────────────────────────────────────
// Uses useRef to avoid getElementById issues in sandboxed environments
function RawUploadZone({ expId, expName, hasData, fileName, onUpload }) {
  const fileRef = useRef(null);
  const [dragOver, setDragOver] = useState(false);
  const [diagMsg, setDiagMsg] = useState(null); // null | {type:"error"|"warn"|"ok", text}

  const processFile = (file) => {
    setDiagMsg(null);

    // ── Basic checks before even reading ──────────────────────────────────
    if (!file) return;

    const ext = file.name.split(".").pop().toLowerCase();
    if (!["xlsx","xls","csv"].includes(ext)) {
      setDiagMsg({ type:"error", text: `❌ Wrong file type: "${file.name}"\n\nExpected: .xlsx or .xls\nReceived: .${ext}` });
      return;
    }
    if (file.size === 0) {
      setDiagMsg({ type:"error", text: "❌ File is empty (0 bytes). Please check the file." });
      return;
    }
    if (file.size > 50 * 1024 * 1024) {
      setDiagMsg({ type:"error", text: "❌ File too large (>50 MB). Please reduce the file size." });
      return;
    }

    setDiagMsg({ type:"ok", text: `⏳ Reading ${file.name} (${(file.size/1024).toFixed(0)} KB)…` });

    const reader = new FileReader();
    reader.onerror = () => {
      setDiagMsg({ type:"error", text: `❌ Browser could not read the file.\n\nTry: close and reopen the file in Excel, then re-save as .xlsx and try again.` });
    };
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target.result);
        if (data.length === 0) {
          setDiagMsg({ type:"error", text: "❌ File read as empty. Try re-saving from Excel as .xlsx" });
          return;
        }

        let wb;
        try {
          wb = XLSX.read(data, { type: "array", cellDates: true });
        } catch(xlsxErr) {
          setDiagMsg({ type:"error", text: `❌ Cannot parse Excel file.\n\nError: ${xlsxErr.message}\n\nFix: Open in Excel → File → Save As → .xlsx format` });
          return;
        }

        if (!wb.SheetNames || wb.SheetNames.length === 0) {
          setDiagMsg({ type:"error", text: "❌ Excel file has no sheets." });
          return;
        }

        const sheetName = wb.SheetNames[0];
        const sheet = wb.Sheets[sheetName];
        const rows = XLSX.utils.sheet_to_json(sheet, { defval: null });

        if (rows.length === 0) {
          setDiagMsg({ type:"error", text: `❌ Sheet "${sheetName}" is empty.\n\nMake sure the first row is a header row and data starts from row 2.` });
          return;
        }

        const cols = Object.keys(rows[0]);
        const required = ["CHICKEN_ID", "TREATMENT_NAME"];
        const missing = required.filter(r => !cols.includes(r));

        if (missing.length > 0) {
          const colList = cols.join(", ") || "(none detected)";
          setDiagMsg({ type:"error", text:
            `❌ Missing required columns: ${missing.join(", ")}\n\n` +
            `Columns found in your file:\n${colList}\n\n` +
            `Required (exact spelling):\n  CHICKEN_ID\n  TREATMENT_NAME\n\nOptional but needed for survival curve:\n  SURVIVAL_TIME`
          });
          return;
        }

        // Check survival data
        const hasSurvival = cols.includes("SURVIVAL_TIME") &&
          rows.some(r => r.SURVIVAL_TIME !== null && r.SURVIVAL_TIME !== undefined && r.SURVIVAL_TIME !== "");
        const extraCols = cols.filter(c => !["CHICKEN_ID","TREATMENT_ID","TREATMENT_NAME","SURVIVAL_TIME"].includes(c));
        const infos = [];
        if (hasSurvival) infos.push("⭐ SURVIVAL_TIME detected — Kaplan-Meier curve will be generated");
        else infos.push("ℹ No SURVIVAL_TIME data — all other phenotypes will be stored for future analysis");
        if (extraCols.length > 0) infos.push(`📐 ${extraCols.length} extra phenotype(s): ${extraCols.join(", ")}`);

        setDiagMsg({ type:"ok", text: `✅ ${file.name}\n${rows.length} animals · ${cols.length} columns\n\n${infos.join("\n")}` });
        onUpload(file);

      } catch(err) {
        setDiagMsg({ type:"error", text: `❌ Unexpected error: ${err.message}` });
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handleDrop = (e) => {
    e.preventDefault(); setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) processFile(file);
  };

  const borderCol = dragOver
    ? GOLD
    : hasData ? "rgba(92,224,122,0.4)" : "rgba(190,165,75,0.25)";

  return (
    <div style={{ marginBottom: 20 }}>
      <div
        onClick={() => fileRef.current && fileRef.current.click()}
        onDragOver={e => { e.preventDefault(); setDragOver(true); }}
        onDragLeave={() => setDragOver(false)}
        onDrop={handleDrop}
        style={{
          padding: "18px 16px", border: `2px dashed ${borderCol}`, borderRadius: 10,
          textAlign: "center", cursor: "pointer", transition: "all 0.2s",
          background: dragOver ? `rgba(190,165,75,0.08)` : hasData ? "rgba(92,224,122,0.04)" : "rgba(190,165,75,0.02)"
        }}>
        <div style={{ fontSize: 22, marginBottom: 6 }}>{hasData ? "✅" : "⬆"}</div>
        <div style={{ fontSize: 12, fontWeight: 600, color: hasData ? "#5CE07A" : GOLD }}>
          {hasData ? `${fileName || "RAW data loaded"} — click or drag to replace` : `Upload ${expName}_RAW.xlsx`}
        </div>
        <div style={{ fontSize: 10, color: "rgba(255,255,255,0.3)", marginTop: 5, lineHeight: 1.6 }}>
          Required: <span style={{ color: "rgba(255,255,255,0.5)" }}>CHICKEN_ID · TREATMENT_NAME</span><br/>
          For survival curve: <span style={{ color: `${GOLD}99` }}>SURVIVAL_TIME</span> · Also stores any extra phenotypes (BW_0, RT_0, GLUCOSE_0…)
        </div>
      </div>

      {/* Diagnostic message */}
      {diagMsg && (
        <div style={{
          marginTop: 10, padding: "12px 14px", borderRadius: 8, fontSize: 11, lineHeight: 1.65,
          whiteSpace: "pre-wrap", fontFamily: "monospace",
          background: diagMsg.type === "error" ? "rgba(224,92,92,0.08)" : "rgba(92,224,122,0.07)",
          border: `1px solid ${diagMsg.type === "error" ? "rgba(224,92,92,0.3)" : "rgba(92,224,122,0.25)"}`,
          color: diagMsg.type === "error" ? "#E07070" : "#7CE0A0"
        }}>
          {diagMsg.text}
          {diagMsg.type === "error" && (
            <div style={{ marginTop: 8, color: "rgba(255,255,255,0.4)", fontFamily: "sans-serif" }}>
              💡 Tip: Open your file in Excel, check the column names match exactly, then File → Save As → Excel Workbook (.xlsx)
            </div>
          )}
        </div>
      )}

      <input
        ref={fileRef}
        type="file"
        accept=".xlsx,.xls"
        style={{ display: "none" }}
        onChange={e => {
          if (e.target.files && e.target.files[0]) processFile(e.target.files[0]);
          e.target.value = "";
        }}
      />
    </div>
  );
}

